 4	import { TemplateDetailsGridProps } from 'src/views/templates/details/tabs/details/TemplateDetailsPage';
 5	import { getTemplateProviderName } from 'src/views/templates/utils/selectors';
 6	
 7	import { TemplateModel } from '@kubevirt-ui/kubevirt-api/console';
