10	import HardwareDevices from '@kubevirt-utils/components/HardwareDevices/HardwareDevices';
11	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
12	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
13	import {
14	  getTemplateSupportLevel,
15	  getTemplateVirtualMachineObject,
16	  replaceTemplateVM,
17	} from '@kubevirt-utils/resources/template';
18	import { NO_DATA_DASH } from '@kubevirt-utils/resources/vm/utils/constants';
19	import { k8sUpdate } from '@openshift-console/dynamic-plugin-sdk';
20	import { DescriptionList } from '@patternfly/react-core';
21	
22	import useEditTemplateAccessReview from '../../../hooks/useIsTemplateEditable';
23	
24	const TemplateDetailsRightGrid: React.FC<TemplateDetailsGridProps> = ({ template }) => {
25	  const { t } = useKubevirtTranslation();
26	  const { isTemplateEditable } = useEditTemplateAccessReview(template);
27	
28	  const providerContent = getTemplateProviderName(template)?.trim()
29	    ? getTemplateProviderName(template)?.trim()
30	    : t('Not available');
31	
32	  const onSubmit = async (updatedVM: V1VirtualMachine) => {
33	    await k8sUpdate({
34	      data: replaceTemplateVM(template, updatedVM),
35	      model: TemplateModel,
36	      name: template?.metadata?.name,
37	      ns: template?.metadata?.namespace,
38	    });
39	  };
40	
41	  return (
42	    <DescriptionList className="pf-v6-c-description-list">
43	      <BootOrderItem template={template} />
44	      <BootSource template={template} />
45	      <VirtualMachineDescriptionItem
46	        descriptionData={providerContent}
47	        descriptionHeader={t('Provider')}
48	      />
49	      <VirtualMachineDescriptionItem
50	        descriptionData={getTemplateSupportLevel(template) || NO_DATA_DASH}
51	        descriptionHeader={t('Support')}
52	      />
53	      <VirtualMachineDescriptionItem
54	        descriptionData={
55	          <HardwareDevices
56	            canEdit={isTemplateEditable}
57	            onSubmit={onSubmit}
58	            vm={getTemplateVirtualMachineObject(template)}
59	          />
60	        }
61	        descriptionHeader={t('Hardware devices')}
62	      />
63	      <AdditionalResources template={template} />
64	    </DescriptionList>
65	  );
66	};
67	export default TemplateDetailsRightGrid;

